-->\n<div class="wp-block-column is-vertically-aligned-center"><!-- wp:group {"backgroundColor":"white","textColor":"black","className":"speech_balloon_right z-index1"} -->\n<div class="wp-block-group speech_balloon_right z-index1 has-black-color has-white-background-color has-text-color has-background"><!-- wp:group -->\n<div class="wp-block-group"><!-- wp:heading {"level":3,"style":{"typography":{"fontSize":"24px"}},"textColor":"vivid-red","className":"is-style-webfont1"} -->\n<h3 class="is-style-webfont1 has-vivid-red-color has-text-color" style="font-size:24px">心から楽しめる内容になっています！</h3>\n<!-- /wp:heading --></div>\n<!-- /wp:group -->\n\n<!-- wp:spacer {"height":10} -->\n<div style="height:10px" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:paragraph {"fontSize":"normal"} -->\n<p class="has-normal-font-size">ダイエットは苦しいというイメージがありますが、このプログラムは本当に心から楽しめる内容になっています！食事もただ制限するだけでなく、日々の食事を楽しみながらダイエットをできるようにアドバイスをしっかりくれるので、<span style="color:#cf2e2e" class="tadv-color">苦しいと思うことがほとんどありませんでした</span>。激しい運動ではなく、効率的に痩せることができるメニューを組んでいただけるので、気付いたら-5キロになってました！本当におすすめです♪</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"verticalAlignment":"center","width":"150px"} -->\n<div class="wp-block-column is-vertically-aligned-center" style="flex-basis:150px"><!-- wp:image {"align":"center","id":2331,"sizeSlug":"medium","linkDestination":"none","className":"is-style-rounded"} -->\n<div class="wp-block-image is-style-rounded"><figure class="aligncenter size-medium"><img src="https://lptemp.com/dx/wp-content/uploads/2021/12/sample-woman03-300x300.jpg" alt="" class="wp-image-2331"/></figure></div>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:group -->\n<div class="wp-block-group"><!-- wp:columns {"verticalAlignment":"center","className":"flx_direc_revs"} -->\n<div class="wp-block-columns are-vertically-aligned-center flx_direc_revs"><!-- wp:column {"verticalAlignment":"center","width":"150px"} -->\n<div class="wp-block-column is-vertically-aligned-center" style="flex-basis:150px"><!-- wp:image {"align":"center","id":2270,"sizeSlug":"medium","linkDestination":"none","className":"is-style-rounded"} -->\n<div class="wp-block-image is-style-rounded"><figure class="aligncenter size-medium"><img src="https://lptemp.com/dx/wp-content/uploads/2021/12/pointing01-300x300.jpg" alt="" class="wp-image-2270"/></figure></div>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"verticalAlignment":"center","width":""} -->\n<div class="wp-block-column is-vertically-aligned-center"><!-- wp:group {"backgroundColor":"white","textColor":"black","className":"speech_balloon_left"} -->\n<div class="wp-block-group speech_balloon_left has-black-color has-white-background-color has-text-color has-background"><!-- wp:group -->\n<div class="wp-block-group"><!-- wp:heading {"level":3,"style":{"typography":{"fontSize":"24px"}},"textColor":"vivid-red","className":"is-style-webfont1"} -->\n<h3 class="is-style-webfont1 has-vivid-red-color has-text-color" style="font-size:24px">サポートしてくれるトレーナーさんがいるからこそだと身を持って体感！</h3>\n<!-- /wp:heading --></div>\n<!-- /wp:group -->\n\n<!-- wp:spacer {"height":10} -->\n<div style="height:10px" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:paragraph {"fontSize":"normal"} -->\n<p class="has-normal-font-size">いつも痩せないといけないとはわかっていても、どうしても運動も食事制限も続かないで挫折をつつけていました。背中を押してもらうつもりで、勇気をもってこのプログラムに参加してみましたが、<span style="color:#cf2e2e" class="tadv-color">今まで苦労していたのがなんだったのかというくらい食事のコントロールや運動を習慣化できるようになりました！</span>これもサポートをしてくれるトレーナーさんがいるからこそだと身を持って体感！自分一人ではできないこともだれかが隣にいてくれると続けられるかもしれません！</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns {"verticalAlignment":"center"} -->\n<div class="wp-block-columns are-vertically-aligned-center"><!-- wp:column {"verticalAlignment":"center","width":""} -->\n<div cl